[Fact]
public async Task DrainAsync_Sequential_PicksUpNewTaskBetweenTasks()
{
    using var repo = TestRepository.Create();
    repo.WriteConfig("dotnet test", []);
    repo.WriteTask("alpha", "# Alpha\n");
    repo.WriteTask("beta", "# Beta\n");
