    var runner = new RecordingTaskRunner();
    var controller = new RelayQueueController(repo.Root, runner);
    runner.AfterRun = () =>
    {
        if (runner.TasksRun.Count == 1)
            controller.Tasks.Add(new RelayTaskItem("delta",
                Path.Combine(repo.Root, "llm-tasks", "delta.md"),
                Path.Combine(repo.Root, "llm-tasks")!, false, []));
